templateSql:
UPDATE orders
        SET status = #{status}
        WHERE order_no IN
        <foreach collection="orderNos" item="orderNo" open="(" separator="," close=")">
            #{orderNo}
        </foreach>

SELECT * FROM (
            SELECT id, name, status FROM users WHERE status = 'active'
        ) active_users

SELECT ${groupField}, COUNT(*) as cnt
        FROM users
        GROUP BY ${groupField}

SELECT COUNT(*) FROM (
            SELECT id FROM users WHERE status = 'active'
        ) active_users
